What does this program print?

```cpp
#include <iostream>

class Box {
    int m_vol{};
public:
    Box(int v) : m_vol{v} {}
    friend Box operator+(const Box& a, const Box& b);
    int vol() const { return m_vol; }
};

Box operator+(const Box& a, const Box& b) {
    return Box{a.m_vol + b.m_vol};
}

int main() {
    Box x{10}, y{25};
    Box z = x + y;
    std::cout << z.vol() << "\n";
    return 0;
}
```

